module serial2parallel
(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output dout_parallel,
    output reg dout_valid
);
    reg [3:0] cnt;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 4'd0;
            dout_valid <= 1'b0;
        end
        else if (cnt == 4'd8) begin
            cnt <= 4'd0;
            dout_valid <= 1'b1;
        end
        else begin
            cnt <= cnt + 1'b1;
            dout_valid <= 1'b0;
        end
    end
    always @(posedge clk) begin
        if (cnt == 4'd0) dout_parallel <= 8'd0;
        else if (cnt <= 4'd8) dout_parallel <= {dout_parallel[6:0], din_serial};
    end
endmodule

module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);
    // ADD YOUR CODE HERE
    // ...
    // ...
    // ...
    reg [3:0] cnt;
    reg start_cnt;
    reg [7:0] neg_divisor;
    reg [15:0] sr;
    always @(posedge clk or negedge rst) begin
        if(!rst) begin
            cnt <= 4'b0;
            start_cnt <= 1'b0;
            neg_divisor <= 8'b0;
            sr <= 16'b0;
        end
        else begin
            if(opn_valid == 1'b1 && cnt == 4'b0 && start_cnt == 1'b0) begin
                if(sign == 1'b1) begin
                    if(dividend[7] == 1'b1) begin
                        sr <= {8'b0, ~dividend + 1'b1};
                    end
                    else begin
                        sr <= {8'b0, dividend};
                    end
                end
                else begin
                    sr <= {8'b0, dividend};
                end
                if(divisor[7] == 1'b1) begin
                    neg_divisor <= ~divisor + 1'b1;
                end
                else begin
                    neg_divisor <= divisor;
                end
                cnt <= 4'b1;
                start_cnt <= 1'b1;
            end
            else if(start_cnt == 1'b1) begin
                if(cnt == 4'b1000) begin
                    cnt <= 4'b0;
                    start_cnt <= 1'b0;
                    if(sign == 1'b1) begin
                        if(dividend[7] == 1'b1) begin
                            sr <= {neg_divisor, 8'b0};
                        end
                        else begin
                            sr <= {8'b0, dividend};
                        end
                    end
                    else begin
                        sr <= {8'b0, dividend};
                    end
                end
                else begin
                    cnt <= cnt + 1'b1;
                    if(sr[15] == 1'b1) begin
                        sr <= {neg_divisor, 8'b0};
                    end
                    else begin
                        sr <= {sr[14:0], 1'b0};
                    end
                end
            end
        end
    end
    always @(posedge clk or negedge rst) begin
        if(!rst) begin
            res_valid <= 1'b0;
        end
        else begin
            if(cnt == 4'b1000) begin
                res_valid <= 1'b1;
            end
            else if(res_valid == 1'b1 && res_ready == 1'b1) begin
                res_valid <= 1'b0;
            end
        end
    end
    always @(*) begin
        if(sign == 1'b1) begin
            if(sr[15] == 1'b1) begin
                result <= {sr[15:0], sr[15:8]};
            end
            else begin
                result <= {neg_divisor, 8'b0};
            end
        end
        else begin
            result <= {sr[15:0], sr[15:8]};
        end
    end
endmodule

module width_8to16
