    input rst_n,
    input valid_in,
    input [7:0] data_in,
    output reg valid_out,
    output reg [15:0] data_out
);

reg [7:0] data_buffer;
reg valid_buffer;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data_buffer <= 8'b0;
        valid_buffer <= 1'b0;
    end
    else if (valid_in) begin
        data_buffer <= data_in;
        valid_buffer <= ~valid_buffer;
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data_out <= 16'b0;
        valid_out <= 1'b0;
    end
    else if (valid_buffer) begin
        data_out <= {data_buffer, data_in};
        valid_out <= 1'b1;
    end
    else begin
        valid_out <= 1'b0;
    end
end

endmodule

