module traffic_light
(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output reg red
);
parameter idle = 2'b00;
parameter s1_red = 2'b01;
parameter s2_yellow = 2'b10;
parameter s3_green = 2'b11;
reg [7:0] cnt;
reg [1:0] state;
reg p_red, p_yellow, p_green;
always @(*) begin
    case (state)
        idle: begin
            state <= s1_red;
            p_red <= 0;
            p_yellow <= 0;
            p_green <= 0;
        end
        s1_red: begin
            p_red <= 1;
            p_yellow <= 0;
            p_green <= 0;
            if (cnt == 3) begin
                state <= s3_green;
            end
            else begin
                state <= s1_red;
            end
        end
        s2_yellow: begin
            p_red <= 0;
            p_yellow <= 1;
            p_green <= 0;
            if (cnt == 3) begin
                state <= s1_red;
            end
            else begin
                state <= s2_yellow;
            end
        end
        s3_green: begin
            p_red <= 0;
            p_yellow <= 0;
            p_green <= 1;
            if (cnt == 3) begin
                state <= s2_yellow;
            end
            else begin
                state <= s3_green;
            end
        end
    endcase
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 10;
    end
    else begin
        if (pass_request && green) begin
            cnt <= 10;
        end
        else begin
            if (!green && p_green) begin
                cnt <= 60;
            end
            else begin
                if (!yellow && p_yellow) begin
                    cnt <= 5;
                end
                else begin
                    if (!red && p_red) begin
                        cnt <= 10;
                    end
                    else begin
                        cnt <= cnt - 1;
                    end
                end
            end
        end
    end
end
assign clock = cnt;
always @(posedge clk or negedge rst_n) begin
    if (rst_n == 0) begin
        red <= 0;
        yellow <= 0;
        green <= 0;
    end
    else begin
        red <= p_red;
        yellow <= p_yellow;
        green <= p_green;
    end
end
endmodule

module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
);

reg [31:0] product;
reg [15:0] multiplier;
reg [15:0] multiplicand;
reg [4:0] shift_count;
reg [1:0] state;
reg done_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        product <= 0;
        multiplier <= 0;
        multiplicand <= 0;
        shift_count <= 0;
        state <= 0;
        done_reg <= 0;
    end else begin
        case (state)
            2'b00: begin // Load inputs
                if (start) begin
                    multiplier <= bin;
                    multiplicand <= ain;
                    shift_count <= 0;
                    state <= 2'b01;
                end
            end
            2'b01: begin // Shift and accumulate
                if (shift_count < 16) begin
                    if (multiplier[0]) begin
                        product <= product + (multiplicand << shift_count);
                    end
                    multiplier <= multiplier >> 1;
                    shift_count <= shift_count + 1;
                end else begin
                    state <= 2'b10;
                end
            end
            2'b10: begin // Output result
                done_reg <= 1;
                state <= 2'b00;
            end
        endcase
    end
end

assign yout = product;
assign done = done_reg;

endmodule

module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output mul_en_out,
    output reg mul_out
);
parameter M = 8, N = 8;
reg [7:0] mul_a_reg, mul_b_reg;
reg mul_en_out_reg;
reg [15:0] partial_prod[N-1:0], temp[N-1:0];
reg [15:0] sum[N-1:0];
reg [16:0] final_sum;
// Input Control
always @(posedge clk) begin
    if (!rst_n) begin
        mul_en_out_reg <= 0;
        mul_a_reg <= 0;
        mul_b_reg <= 0;
    end
    else begin
        mul_en_out_reg <= {mul_en_out_reg[N-2:0], mul_en_in};
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end
end
assign mul_en_out = mul_en_out_reg[N-1];
// Input Registers
always @(posedge clk) begin
    if (!rst_n) begin
        mul_a_reg <= 0;
        mul_b_reg <= 0;
    end
    else begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end
end
// Partial Product Generation
genvar i;
generate
    for (i = 0; i < N; i = i + 1) begin : gen_partial_products
        assign temp[i] = {8'b0, mul_b_reg[i]} & mul_a_reg;
    end
endgenerate
// Partial Sum Calculation
always @(posedge clk) begin
    if (!rst_n) begin
        for (int i = 0; i < N; i = i + 1)
            sum[i] <= 0;
        final_sum <= 0;
    end
    else begin
        for (int i = 0; i < N; i = i + 1)
            sum[i] <= (i == 0) ? temp[i] : sum[i-1] + temp[i];
        final_sum <= sum[N-1];
    end
end
// Final Product Calculation
always @(posedge clk) begin
    if (!rst_n)
        mul_out <= 0;
    else
        mul_out <= mul_en_out_reg ? final_sum : 0;
end
endmodule

module parallel2serial
(
    input clk,
    input rst_n,
    input [3:0] d,
    output reg valid_out,
    output dout
);

reg [3:0] shift_reg;
reg [2:0] counter;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        shift_reg <= 4'b0000;
        counter <= 3'b000;
        valid_out <= 1'b0;
    end
    else begin
        if (counter == 3'b011) begin
            shift_reg <= d;
            counter <= 3'b000;
            valid_out <= 1'b1;
        end
        else begin
            counter <= counter + 1;
            shift_reg <= {shift_reg[2:0], shift_reg[3]};
            valid_out <= 1'b0;
        end
    end
end

assign dout = shift_reg[3];

endmodule

module div_16bit
(
    input [15:0] A,
    input [7:0] B,
    output [15:0] result,
    output [15:0] odd
);
// Create two registers, a_reg and b_reg, to store the values of A and B.
reg [15:0] a_reg;
reg [7:0] b_reg;
// Assign the value of A to a_reg.
always @(*) a_reg = A;
// Assign the value of B to b_reg.
always @(*) b_reg = B;
// Compare the upper M bits of a_reg and b_reg.
wire [15:0] remainder;
wire [15:0] diff;
// if a_reg[N:0] is greater than b_reg,
// set the quotient bit to 1 and subtract b_reg from a_reg.
// Otherwise, set the quotient bit to 0.
// Set the remainder to the difference.
assign {diff, remainder} = a_reg - b_reg;
// Concatenate the remainder with the next bit of a_reg,
// and repeat the process until all bits of a_reg are processed.
assign {odd, result} = {remainder, a_reg} << 1;
// ---------------------------------------------------------
// Time scale
`timescale 1ns/10ps
// ---------------------------------------------------------
// 16-bit divider module with combinational logic
// ---------------------------------------------------------
// 16-bit dividend and 8-bit divisor input signals
// and 16-bit quotient and remainder output signals
module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);
dmodule
endmodule

module multi_8bit
(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);
parameter BIT_WIDTH = 8;
parameter PRODUCT_WIDTH = 16;
reg [7:0] A_shifted;
reg [3:0] i;
always @(*) begin
    // Initialize product to 0
    product = 0;
    // Iterate through each bit of the multiplier
    for (i = 0; i < BIT_WIDTH; i = i + 1) begin
        // Check if the current bit of the multiplier is set
        if (B[i] == 1) begin
            // Condition met: Add the shifted multiplicand to the product
            product = product + (A << i);
        end
    end
    // Loop invariant: product = A * B
    // End of loop
end
endmodule

module fsm
(
    input IN,
    input CLK,
    input RST,
    output MATCH
);
    // DEFINE STATE ENUM (DO NOT MODIFY)
    parameter [2:0] IDLE = 3'b000;
    parameter [2:0] S1   = 3'b001;
    parameter [2:0] S10  = 3'b010;
    parameter [2:0] S101 = 3'b011;
    parameter [2:0] S1011 = 3'b100;

    // DEFINE STATE REGS (DO NOT MODIFY)
    reg [2:0] state;
    reg [2:0] next_state;

    // DEFINE MATCH REG (DO NOT MODIFY)
    reg next_match;

    // SEQUENTIAL LOGIC (DO NOT MODIFY)
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            match <= 1'b0;
        end else begin
            state <= next_state;
            match <= next_match;
        end
    end

    // COMBINATIONAL LOGIC (DO NOT MODIFY)
    always @(*) begin
        case (state)
            IDLE: begin
                next_state = (in == 1'b1) ? S1 : IDLE;
                next_match = 1'b0;
            end
            S1: begin
                next_state = (in == 1'b0) ? S10 : IDLE;
                next_match = 1'b0;
            end
            S10: begin
                next_state = (in == 1'b1) ? S101 : IDLE;
                next_match = 1'b0;
            end
            S101: begin
                next_state = (in == 1'b1) ? S1011 : IDLE;
                next_match = 1'b0;
            end
            S1011: begin
                next_state = (in == 1'b0) ? IDLE : S1011;
                next_match = (in == 1'b0) ? 1'b0 : 1'b1;
            end
            default: begin
                next_state = IDLE;
                next_match = 1'b0;
            end
        endcase
    end
endmodule

