module multi_pipe_4bit
#(
    parameter size = 4
)
(
    input clk,
    input rst_n,
    input mul_a,
    input mul_b,
    output reg mul_out
);
    parameter size = 4;
    // input
    wire [size-1:0] mul_a_extend = {{size{1'b0}}, mul_a};
    wire [size-1:0] mul_b_extend = {{size{1'b0}}, mul_b};
    // genvar
    wire [size-1:0] pp[0:size-1]; // partial product
    // pp[i]
    genvar i;
    generate
        for (i=0; i<size; i=i+1) begin : gen_for_partial_product
            assign pp[i] = (mul_b_extend[i]) ? (mul_a_extend << i) : 'd0;
        end
    endgenerate
    // reg
    reg [2*size-1:0] reg_pp[0:size-2]; // adder
    // reg_pp[i]
    integer j;
    always @(posedge clk, negedge rst_n) begin
        if (!rst_n) begin
            for (j=0; j<size-1; j=j+1) begin
                reg_pp[j] <= 'd0;
            end
        end
        else begin
            for (j=0; j<size-1; j=j+1) begin
                reg_pp[j] <= pp[j] + pp[j+1];
            end
        end
    end
    // mul_out
    always @(posedge clk, negedge rst_n) begin
        if (!rst_n) begin
            mul_out <= 'd0;
        end
        else begin
            mul_out <= reg_pp[0] + reg_pp[1];
        end
    end
endmodule

module calendar
(
    input CLK,
    input RST,
    output reg [5:0] Hours,
    output reg [5:0] Mins,
    output reg [5:0] Secs
);
reg [5:0] Secs_next;
reg [5:0] Mins_next;
reg [5:0] Hours_next;
always @(posedge CLK or posedge RST) begin
    if (RST)
        Secs <= 6'd0;
    else if (Secs == 6'd59)
        Secs <= 6'd0;
    else
        Secs <= Secs + 1;
end
always @(posedge CLK or posedge RST) begin
    if (RST)
        Mins <= 6'd0;
    else if (Mins == 6'd59 && Secs == 6'd59)
        Mins <= 6'd0;
    else if (Secs == 6'd59)
        Mins <= Mins + 1;
    else
        Mins <= Mins;
end
