assign carry_stage[0] = {1'b0, (adda_reg[0] & addb_reg[0])}; // AND operation for the carry at pipeline stage 0.
assign sum_stage[1] = sum_stage[0] ^ carry_stage[0][63:0]; // XOR operation for the sum at pipeline stage 1.
assign carry_stage[1] = {1'b0, (sum_stage[0] & carry_stage[0][63:0])} + carry_stage[0]; // AND and addition operation for the carry at pipeline stage 1.
// Pipeline registers update logic
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        adda_reg[0] <= 64'b0;
        addb_reg[0] <= 64'b0;
